var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"여긴.......","JPN":"ここは……","ENG":"Where am I....?","TWN":"這裡……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"설마....... 변이인자 연구시설......?","JPN":"まさか……変異因子研究施設……？","ENG":"Is this... The mutation factor laboratory...?","TWN":"難道是……變異因子研究設施嗎……?"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"큿......! 으윽.......","JPN":"くっ……！　ううっ……","ENG":"Ack...! Ugh...","TWN":"唔……！呃呃……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"괘, 괜찮아요? 안색이 파란데......?","JPN":"だ、大丈夫ですか？　顔が真っ青ですよ……？","ENG":"Are you okay? You look pale...","TWN":"妳、妳沒事吧？妳的臉色很差耶……？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히, 힘드시면 제가 짐이라도 좀 들어 드릴까요?","JPN":"つ、辛いなら、ヒミコが荷物でも持ちましょうか？","ENG":"I can carry your stuff if you're too tired!","TWN":"妳、妳累的話，要不要我幫妳拿一下行李？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"......아, 아니에요.","JPN":"……い、いいえ。","ENG":"It's okay...","TWN":"……不、不用了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그냥 좀 현기증이 밀려와서...... 이제 괜찮아요.","JPN":"ちょっとめまいがしただけなので……今は大丈夫です。","ENG":"I'm just a little dizzy... But I'm fine now.","TWN":"我只是有點頭暈……現在已經沒事了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"걱정 끼쳐드려 죄송합니다.......","JPN":"心配かけてごめんなさい……","ENG":"Sorry to worry you...","TWN":"對不起，讓你們擔心了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저...... 별로 도움은 안 되겠지만...... 그래도 마음만은 응원하고 있으니까요.......","JPN":"あまり頼りにならないかもしれませんが……でも、応援したい気持ちはありますから……","ENG":"Um... I know I'm not very useful... But I hope I can at least offer emotional support...","TWN":"我……雖然幫不了什麼忙……但我會在心裡支持妳的……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"제가 필요하면 언제든지 불러주세요.","JPN":"ヒミコが必要な時は、いつでも呼んでください。","ENG":"You can call me whenever you need help.","TWN":"有什麼需要我的地方，隨時都可以叫我。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저, 저도 도와드릴게요! 말만 하세요!","JPN":"あ、秋も手伝います！　何なりと言ってください！","ENG":"I'm happy to help! Just say the word!","TWN":"我，我也會幫妳！儘管開口就對了！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"싸, 싸움만 빼고요.......","JPN":"け、ケンカだけは除いてですが……","ENG":"Anything except fighting, though...","TWN":"除、除了幫妳戰鬥以外……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 의뢰인! 듣고 있나?","JPN":"おい、依頼人！　聞こえるか？","ENG":"Hey, Blackbird! You there?","TWN":"委託人嗎！你在聽嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"마지막 발신지에 거의 다 도착한 것 같아. 자세한 현재 위치를 알려 주면 좋겠는데?","JPN":"最後の発信地にもうすぐ着くぞ。詳しい現在位置を教えてくれ。","ENG":"We're almost at the source of your signal. Tell us your exact location.","TWN":"我們快到最後一個發信地了。能告訴我你現在的位置嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......어이?","JPN":"……おい？","ENG":"Hello?","TWN":"……嗯？喂？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설마 벌써 당해 버린 건 아니겠지?","JPN":"まさか、もうやられてるんじゃないだろうな？","ENG":"Are you dead already?","TWN":"難道他已經被幹掉了嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"응답해! 블랙 버드!","JPN":"応答せよ！　ブラックバード！","ENG":"Come in, Blackbird!","TWN":"回答我啊！黑鳥！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......살아 있으니까 소리 좀 그만 지르게, 메이슨.","JPN":"……生きてるから、大声出すの止めてくれ、メイソン。","ENG":"...I'm still alive so can you stop shouting, Mason?","TWN":"……我還活著！別叫了，梅森。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......다행이군. 혹시라도 늦었으면 어쩌나 했는데.","JPN":"……よかった。手遅れにならないか心配したんだ。","ENG":"...That's good. I thought maybe we were too late.","TWN":"……真是萬幸，要是晚了一步，我都不知道該怎麼辦了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금 상황은 어떻지?","JPN":"今の状況はどうだ？","ENG":"How are things over there?","TWN":"現在情況如何？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"별로 쾌적하진 않군.","JPN":"あまり快適ではないな。","ENG":"Could be better.","TWN":"不是很好。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"호위 팀은 아마 전멸한 것 같아.","JPN":"護衛チームはたぶん全滅したようだ。","ENG":"I think the escort team might have been annihilated.","TWN":"護衛隊恐怕已經全軍覆沒了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아마......?","JPN":"たぶん……？","ENG":"You think...?","TWN":"恐怕……？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"이 친구들, 날 강제로 창고에 처넣고는 밖에서 빗장을 질러 버리더군.","JPN":"あいつら、俺を倉庫に無理やり押し込んでは外から入れないようにしたんだ。","ENG":"These guys shoved me into the warehouse and bolted the door from outside.","TWN":"他們強行把我塞進倉庫後，還從外面把門拴上了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그만두라고 고래고래 소리를 질렀는데 명령도 싹 무시하고 말이지.","JPN":"散々やめろと叫んだのに、命令は全て無視された。","ENG":"I told them to stop, but they completely ignored my orders.","TWN":"我一直叫他們住手，但他們無視了我的命令。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그 후로도 꽤 오랫동안 싸우는 소리가 들렸는데.......","JPN":"それからも、かなり長い間戦ってる音がしていたが……","ENG":"Then I heard them fighting for quite a while...","TWN":"那之後，我聽到戰鬥聲持續了很久……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"이젠 조용해졌군.","JPN":"今はとても静かだ。","ENG":"But it's quiet now.","TWN":"但現在已經安靜下來了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"기회가 되면 랭글리에서 상사의 명령이란 게 얼마나 중요한 건지 다시 한 번 가르쳐 주고 싶었는데.......","JPN":"機会があれば、ラングレーでの上司命令が\\nどれだけ重要か叩き込みたかったのに……","ENG":"If we got through this, I wanted to show them how important it is to follow orders from a high-ranking officer in Langley...","TWN":"如果有機會的話，我想再次告訴他們，上司的命令有多麼重要……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"아마도 이젠 그럴 기회가 없을 것 같아.","JPN":"たぶん、もうそんな日は来ないようだ。","ENG":"But I doubt I'll have that chance now...","TWN":"不過，現在已經沒有這樣的機會了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......괜찮은 친구들이군.","JPN":"……なかなか立派な奴らじゃないか。","ENG":"They sound like honorable fellas.","TWN":"……他們都是不賴的朋友們啊。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"정보부 요원답지 않게 말이야.","JPN":"情報局員らしくないところがな。","ENG":"Not exactly what I expected from spooks like you.","TWN":"簡直不像是情報部的傢伙。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그렇지. 정보부 요원이라면 바퀴벌레 같은 생명력이 미덕이지.","JPN":"だな。　情報局員なら、ゴキブリ並みの生命力が美徳だというのに。","ENG":"I know, right? We in the intel community usually value survival over everything else. Like cockroaches.","TWN":"是啊，如果是情報部的人，要有像蟑螂一樣的生命力才是美德吧。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......나처럼 말이야.","JPN":"……俺のようにな。","ENG":"...Like me.","TWN":"……就像我一樣。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그러니까 꼭 구해 달라고.","JPN":"だから、助けてほしい。","ENG":"So can you please come save me?","TWN":"所以我一定會等到你們來救我！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"아득바득 살아나가서, 이 개자식들에게 합중국의 분노가 어떤 건지 알려줘야 하니까 말이지.","JPN":"意地でも生き延びて、このクソ野郎どもに合衆国の怒りというものを思い知らせてやりたいからな。","ENG":"I need to get out of here so I can show them the full wrath of Uncle Sam.","TWN":"我會拼命活下去，好讓這些雜碎們瞧瞧合眾國發怒的樣子。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 발신 좌표는 확인했다.","JPN":"了解。発信座標は確認した。","ENG":"Fine. I got the coordinates.","TWN":"很好，已確認發信座標。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 숨죽이고 잘 숨어 있으라고. 금방 갈 테니까.","JPN":"なんとか息を潜めて隠れていろよ。すぐに行くからな。","ENG":"Stay low and out of sight. We'll be there soon.","TWN":"那你就屏住呼吸躲好吧，我馬上就過去。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>HQ, 응답하라! 여기는 RK 직속 제 4 소대!</color>","JPN":"<color=#ffd34c>HQ、応答せよ！　こちらはRK直属の第4小隊！</color>","ENG":"<color=#ffd34c>HQ, come in! This is Platoon 4 from RK!</color>","TWN":"<color=#ffd34c>HQ， 請回答！ 這裡是RK直屬的第4小隊。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>미확인 무장인원들을 확인했다! 교전 지시 바란다!</color>","JPN":"<color=#ffd34c>未確認の武装勢力を確認した！　交戦の指示を要請する！</color>","ENG":"<color=#ffd34c>We've spotted unidentified armed combatants! Requesting permission to engage!</color>","TWN":"<color=#ffd34c>這裡確定有不明武裝人員！ 希望下達交戰指示！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 HQ, 비디오 데이터로 볼 때 작전 목표에서 탈출한 용병, 카운터 연합세력으로 보인다.</color>","JPN":"<color=#ffd34c>こちらはHQ、ビデオデータを見る限り、作戦目標から脱出した傭兵とカウンターの連合勢力と見られる。</color>","ENG":"<color=#ffd34c>This is HQ. Based on the video feed, they seem to be a coalition of Counters and the mercenaries who went rogue from the objective area.</color>","TWN":"<color=#ffd34c>這裡是HQ，從錄影記錄的資料來看，對方是從作戰目標中逃脫出來的傭兵和制裁者的聯合勢力。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>1급 적성대상으로 분류, 작전 방해요소가 되기 전에 모든 자원을 투입하여 즉시 소거하라!</color>","JPN":"<color=#ffd34c>1級の適性対象として分類。作戦の妨害要素になる前にすべての資源を投入し、直ちに消去せよ！</color>","ENG":"<color=#ffd34c>They've been designated Class 1 hostiles. Deploy all resources and eliminate them before they present LIMFACs to the mission!</color>","TWN":"<color=#ffd34c>列為一級敵對對象，直到作戰出現困難為止，投入我方全部資源，立即消滅他們。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>라져. 서프레션 프로토콜 발동 후 중형 리플레이서 붕괴체를 동시 투입하겠다. 이상!</color>","JPN":"<color=#ffd34c>ラジャー。サプレッション・プロトコルの発動後、中型リプレイサー崩壊体を同時に投入する。以上！</color>","ENG":"<color=#ffd34c>Roger. We'll deploy the heavy Replacer Collapsers after executing the suppression protocol. Over!</color>","TWN":"<color=#ffd34c>了解，發動抑制協議後，投入克隆崩壞體。完畢。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 아저씨!","JPN":"ねえ、おじさん！","ENG":"Hey, mister!","TWN":"喂！大叔！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 다가오고 있어! ......엄청 큰데?!","JPN":"何かが近づいてきてる！……ものすごく大きいけど！？","ENG":"Something's headed our way! ...And it's big!","TWN":"似乎有什麼正在靠近！……而且還非常巨大？？"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"비장의 카드를 꺼내든 걸 보니 놈들도 몸이 꽤 달아오른 모양이군.","JPN":"切り札を出したということは、奴らもかなり躍起になっているようだな。","ENG":"They must be feeling the heat if they're bringing out their big guns.","TWN":"把底牌都亮出來了，看來這些傢伙很激動呢。"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 이 정도로 꼬리 내릴 것 같으면 시작도 안 했지!","JPN":"だが、これくらいで尻尾を巻くくらいなら、そもそも始めてなどいない！","ENG":"But we wouldn't have gotten started if we were going to back down already!","TWN":"但如果這種程度就放棄的話，我們從一開始就不會戰鬥了。"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 얼간이 삼총사들! 돈 값 할 시간이다!","JPN":"おい、三馬鹿トリオ！　働く時間だ！","ENG":"Hey! Moe, Larry and Curly! It's finally time to earn your keep!","TWN":"喂！傻瓜三劍客！拿了錢該做事了！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이봐, 메이슨! 저거 그때 웬 벌레 같은 놈이랑 같이 쳐들어 온 그놈들 아냐?","JPN":"おい、メイソン！　あれはこの前、虫みたいなのと一緒に押しかけてきた奴らじゃないか？","ENG":"Hey, Mason! Didn't we see these guys with those bug-like monsters?","TWN":"喂，梅森！他們之前不是像蟲子一樣，一起攻過來的東西嗎？"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잘 아는군! 한 번 상대해봤으니 이번에도 문제없겠지?","JPN":"そのとおり！　一度相手したことあるんだし、今回も問題ないよな？","ENG":"That's right! You'll be fine since you fought them before, right?","TWN":"那你們都很熟悉了吧！既然都交手過一次了，這次應該也沒問題吧？"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"아, 아니, 그런 계산이 통할 상대가 아닌 거 같은데?","JPN":"い、いや。経験値でなんとかなるもんじゃないと思うが。","ENG":"Um... I don't think it's safe to assume things like that!","TWN":"不、不是吧，那次交手好像也不算數吧？"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이, 이 녀석들이 나올 거란 말은 없었잖아!","JPN":"あいつらが相手だとは聞いてない！","ENG":"You never told us we'd have to fight these guys!","TWN":"你、你沒說這些傢伙會出來戰鬥啊！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병 일이란 게 다 그렇지. 남의 돈 먹기가 쉬운 줄 아나?","JPN":"傭兵の仕事ってのは、そんなもんだろ？　人様のお金をもらうのは簡単じゃないんだ。","ENG":"What did you expect? You think making money is easy?","TWN":"當傭兵不就是這樣嗎？你以為別人的錢很好賺嗎？"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다 본인이 원해서 온 거니까 불평하지 말라고!","JPN":"自分から願い出たんだから、つべこべ言うな！","ENG":"You're the ones who wanted to come with us, so don't you dare complain!","TWN":"你們不都是自願的嗎？不要抱怨了！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"카운터 아가씨들도 준비됐나?!","JPN":"カウンターの嬢ちゃんたちも準備できたか！？","ENG":"Are you Counter ladies ready too?","TWN":"制裁者的各位女士們也準備好了吧？！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물론!","JPN":"もちろん！","ENG":"You bet!","TWN":"當然！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어...... 저는 시간이 좀 필요한 거 같은데...... 안 되겠죠?","JPN":"えっと……エイミーは時間が少し必要なんだけど……ダメだよね？","ENG":"Um... I need a bit more time... But that's probably not an option, is it?","TWN":"呃……我好像需要一點時間……可以嗎？"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잘 아는군. 중형 붕괴체는 그쪽에 맡기지.","JPN":"よく知っているじゃないか。中型崩壊体はそっちに任せる。","ENG":"You bet. I'll leave the medium collapsers to you.","TWN":"知道了，那麼中型崩壞體就交給你們了。"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이번에도 잘 부탁한다고!","JPN":"今回もよろしく頼むぞ！","ENG":"Good luck!","TWN":"這次也拜託你們了啊！"},"stage":{"bg":"LAB_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};